 17→  if (projectId) {
 18→    conditions.push('i.project_id = ?');
 19→    params.push(projectId);
 20→  }
 21→  if (sessionId) {
 22→    conditions.push('i.session_id = ?');
 23→    params.push(sessionId);
 24→  }
 25→  if (type) {
 26→    conditions.push('i.type = ?');
 27→    params.push(type);
 28→  }
 29→
 30→  const where = `WHERE ${conditions.join(' AND ')}`;
 31→  const insights = db.prepare(`
 32→    SELECT i.id, i.session_id, i.project_id, i.project_name, i.type, i.title, i.content,
 33→           i.summary, i.bullets, i.confidence, i.source, i.metadata, i.timestamp,
 34→           i.created_at, i.scope, i.analysis_version, i.linked_insight_ids
 35→    FROM insights i
 36→    JOIN sessions s ON i.session_id = s.id
 37→    ${where}
 38→    ORDER BY i.timestamp DESC
 39→    LIMIT ? OFFSET ?
 40→  `).all(...params, parseIntParam(limit, 100), parseIntParam(offset, 0));
 41→
 42→  return c.json({ insights });
 43→});
