 45→app.post('/', async (c) => {
 46→  const db = getDb();
 47→  const body = await c.req.json<{
 48→    sessionId: string;
 49→    projectId: string;
 50→    projectName?: string;   // optional — defaults to ''
 51→    type: string;
 52→    title: string;
 53→    content: string;
 54→    summary?: string;       // optional — defaults to ''
 55→    bullets?: string[];
 56→    confidence?: number;    // optional — defaults to 0
 57→    metadata?: Record<string, unknown>;
 58→  }>();
 59→
 60→  // Validate required string fields
 61→  const required = ['sessionId', 'projectId', 'type', 'title', 'content'] as const;
 62→  for (const field of required) {
 63→    if (!body[field] || typeof body[field] !== 'string') {
 64→      return c.json({ error: `Missing or invalid field: ${field}` }, 400);
 65→    }
 66→  }
 67→
 68→  // Validate type is one of the known insight types
 69→  if (!VALID_TYPES.includes(body.type as typeof VALID_TYPES[number])) {
 70→    return c.json({ error: `type must be one of: ${VALID_TYPES.join(', ')}` }, 400);
 71→  }
 72→
 73→  // Validate confidence is a finite number if provided
 74→  if (body.confidence !== undefined && (typeof body.confidence !== 'number' || !Number.isFinite(body.confidence))) {
 75→    return c.json({ error: 'confidence must be a finite number' }, 400);
 76→  }
 77→
 78→  const id = randomUUID();
 79→  const now = new Date().toISOString();
 80→
 81→  try {
 82→    db.prepare(`
 83→      INSERT INTO insights (
 84→        id, session_id, project_id, project_name, type, title, content,
 85→        summary, bullets, confidence, source, metadata, timestamp, created_at
 86→      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'llm', ?, ?, ?)
 87→    `).run(
 88→      id,
 89→      body.sessionId,
 90→      body.projectId,
 91→      body.projectName ?? '',
 92→      body.type,
 93→      body.title,
 94→      body.content,
 95→      body.summary ?? '',
 96→      body.bullets ? JSON.stringify(body.bullets) : null,
 97→      body.confidence ?? 0,
 98→      body.metadata ? JSON.stringify(body.metadata) : null,
 99→      now,
100→      now,
101→    );
102→  } catch (err) {
103→    if (err instanceof Error && err.message.includes('FOREIGN KEY constraint failed')) {
104→      return c.json({ error: 'Invalid sessionId or projectId' }, 400);
105→    }
106→    throw err;
107→  }
108→
109→  return c.json({ id }, 201);
110→});
111→
112→app.delete('/:id', (c) => {
113→  const db = getDb();
114→  const result = db.prepare('DELETE FROM insights WHERE id = ?').run(c.req.param('id'));
115→  if (result.changes === 0) return c.json({ error: 'Not found' }, 404);
116→  return c.json({ ok: true });
117→});
118→
119→export default app;
